var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"기록에 따르면, 이 근처부터 에리두 주민들의 생활권이었다고 해요.","JPN":"記録によると、この辺りはエリドゥの住民たちの生活圏内だったそうです。","ENG":"According to records, this should be where the residents of Eridu lived.","TWN":"根據紀載，從這一帶開始曾經是埃里都居民的生活圈。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"지금은 메마른 사막이지만, 옛날에는 항구도시였다고도 하더라고요.","JPN":"今は砂漠化していますが、かつては港町だったと言われています。","ENG":"It's a dry desert now, but they say it used to be a port city.","TWN":"雖然現在是沙漠之地，但以前聽說是港口城市的。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그리고 여기가 에리두로 향하는 입구 중 하나였고…….","JPN":"そして、ここがエリドゥに入るための、入口の一つ……","ENG":"And right here was one of the entrances to Eridu...","TWN":"而這裡就是通往埃里都的其中一個入口……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아무튼, 이 근처가 에리두가 있었던 터로 추정되는 곳이에요.","JPN":"とにかく、ここ一帯はエリドゥがあったと思われる場所です。","ENG":"Anyway, this area is believed to be where Eridu was located.","TWN":"總之，這附近很可能就是埃里都的所在地。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"모래바람이 더 강해졌다. 분명 침식파 밀도도 더 높아졌겠지.","JPN":"砂嵐がさらに勢いを増した。侵食波の密度も高くなっただろうな。","ENG":"The sandstorm has gotten stronger. And with it, the Corruption ray density must have also increased.","TWN":"沙塵暴變更強了，這就表示侵蝕波密度也提升了。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"나는 버틸 수 있지만…… 네가 걱정이로군.","JPN":"私はまだ耐えられるが、君は大丈夫か。","ENG":"I'm able to endure it, but... I'm worried about you.","TWN":"我是還撐得住…但我擔心你…"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"괜찮아요. 이터니움 쉴드도 빵빵하다고요!","JPN":"大丈夫ですよ。エタニウムシールドも満タンですので！","ENG":"I'm okay. There's still a lot of charge left in my Eternium shield!","TWN":"我沒問題，永恆之金護盾也還很堅固呢！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이 정도는 버틸 만해요!","JPN":"このくらいなら、耐えられます！","ENG":"I'll be fine!","TWN":"還撐得住的！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"게다가 에리두의 존재를 직접 확인하러 가는 건데, 손가락만 빨고 있을 수는 없잖아요?","JPN":"なにより、エリドゥの存在をこの目で確認しようというのに、お荷物になるわけにはいかないじゃないですか？","ENG":"Plus, I'm going to see Eridu with my own eyes. I can't miss out on an opportunity like this!","TWN":"而且我要親眼確認埃里都的存在，怎麼可以半途而廢呢？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"옛날엔 이터니움 쉴드도 정말 귀한 물건이라 함부로 쓰기가 어려웠는데.","JPN":"かつては、エタニウムシールドはとても貴重なもので、簡単に使えるものではなかった。","ENG":"Eternium shields used to be so rare that we couldn't use them so recklessly.","TWN":"在以前，永恆之金護盾可是很珍貴，而且難以取得的。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"세상이 참 편해졌군.","JPN":"世の中が便利になったものだな。","ENG":"Oh, how the world has changed.","TWN":"世界變得很方便呢。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"얼굴만 보면 저랑 비슷한 나이대인 것 같은데, 진짜 세대 차이가…….","JPN":"見た目は私とそんなに変わらないのに、本当にジェネレーションギャップがありますよね……","ENG":"Just by looking at your appearance, you look around my age. But this is where I feel a generation gap...","TWN":"光看臉的話，感覺你跟我年紀差不多，但真的是有代溝……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내가 할 말이다. 이건 꼭 인솔 교사 느낌이잖아.","JPN":"それはこちらのセリフだ。これではまるで、遠足の引率者も同然ではないか。","ENG":"Same here. I feel like I'm the guide here.","TWN":"我才想說，怎麼搞得像是我帶隊一樣？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"길은 네가 알고 있는데 왜 내가 앞장을…….","JPN":"道案内をするのは君のはずなのに、どうして私が先頭に……","ENG":"Why am I in front when you know the path–","TWN":"明明是你知道路，怎麼是我在前頭……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"또다시 소리가…….","JPN":"まただ、この音……","ENG":"It's that sound again...","TWN":"又是侵蝕體的聲……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"윽……!","JPN":"うっ……！","ENG":"Ugh...!","TWN":"唔……！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아디트야 님! 정신 차리세요!","JPN":"アーディティヤ様！　しっかりしてください！","ENG":"Miss Aditya! Are you okay?!","TWN":"阿迪亞！你振作一點！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>따라오십시오.</color>","JPN":"<color=#ff3636>ついてきてください。</color>","ENG":"<color=#ff3636>Follow me.</color>","TWN":"<color=#ff3636>跟我來吧。</color>"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"허억…… 허억…….","JPN":"はあ……はあ……","ENG":"*Huff* *Huff*","TWN":"呼呼……呼呼……"},"stage":{"bg":"CITY_CENTER3","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};